import React, { useState } from "react";
// 1. IMPORTAÇÕES - Garanta que o nome das variáveis em constants.js sejam exatamente estes
import { NOME_APP, STATUS_META, CSS } from "./utils/constants";
import { LS, san } from "./utils/helpers";

// 2. FUNÇÃO PRINCIPAL
export default function App() {
  const [screen, setScreen] = useState("home");
  const [orders, setOrders] = useState([]);
  const [cart, setCart] = useState([]);

  return (
    <div className="App">
       <style>{CSS}</style>

       {screen === "home" && (
         <Home 
           NOME_APP={NOME_APP}
           clientUser={null}
           orders={orders}
           todayOrds={[]}
           maintenanceMode={false}
           handleLogoClick={() => console.log("Logo clicado")}
           calcPontos={() => 0}
           cart={cart}
           setScreen={setScreen}
           onPedido={() => setScreen("pedido-info")}
           onLogin={() => setScreen("client-login")}
         />
       )}
    </div>
  );
}

// 3. COMPONENTE HOME (Agora está fora do App, no nível principal)
export function Home({ onLogin, onPedido, clientUser, orders, todayOrds, maintenanceMode, handleLogoClick, NOME_APP, calcPontos, cart, setScreen }) {
  return (
    <div style={{ fontFamily:"'Nunito',sans-serif",background:"#FDF6FB",minHeight:"100vh" }}>
      <header style={{ background:"#fff",borderBottom:"2px solid #FFF0F8",padding:"14px 18px",display:"flex",justifyContent:"space-between",alignItems:"center" }}>
        <span style={{ fontSize:22,fontWeight:900,color:"#E91E8C",cursor:"pointer" }} onClick={handleLogoClick}>{NOME_APP}</span>
        <div onClick={() => cart.length > 0 ? setScreen("pedido-cart") : null}>
          🛒 {cart.length}
        </div>
      </header>
      <div style={{ padding:"20px 18px" }}>
        <h2>{clientUser ? `Bem-vinda, ${clientUser.nome}` : "Bem-vinda!"}</h2>
        <button onClick={onPedido}>🎂 Fazer Pedido</button>
        <button onClick={onLogin}>👤 Entrar</button>
      </div>
    </div>
  );
}

